export type Currency = 'TL' | 'EUR';

export interface Asset {
  id: string;
  type: 'Banka' | 'Fon';
  name: string;
  subType: string;
  currency: Currency;
  amount: number;
  included: boolean;
}

export interface Check {
  id: string;
  dueDateStr: string;
  valor: number;
  effectiveDateStr: string;
  amount: number;
  desc: string;
}

export interface RecurringRule {
  id: string;
  type: 'income' | 'expense';
  startDate: string;
  amount: number;
  desc: string;
  freq: 'weekly' | 'monthly';
  weekDays?: number[]; // 1-7 (Mon-Sun)
  monthType?: 'fixed' | 'special';
  fixedDay?: number;
  specialOrd?: string;
  specialDay?: string;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  date: string;
  amount: number;
  desc: string;
  currency: Currency;
  source?: 'excel' | 'manual';
  sourceTab?: string;
}

export interface CustomTab {
  id: string;
  name: string;
}

export type ProjectionType = 'daily' | 'weekly' | 'monthly';

export interface FlowPeriod {
  start: Date;
  end: Date;
  label: string;
  incomes: number;
  expenses: number;
  balance: number;
  details: Record<string, number>;
}

import { Asset, Check, RecurringRule, Transaction, FlowPeriod, ProjectionType, Currency } from '../types';

export const formatMoney = (n: number, currency: Currency = 'TL') => {
  return n.toLocaleString('tr-TR', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
    style: 'currency',
    currency: currency === 'TL' ? 'TRY' : 'EUR'
  });
};

export const toLocalYMD = (date: Date) => {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
};

export const getNextBusinessDay = (date: Date) => {
  const d = new Date(date);
  const day = d.getDay();
  if (day === 6) d.setDate(d.getDate() + 2); // Saturday -> Monday
  else if (day === 0) d.setDate(d.getDate() + 1); // Sunday -> Monday
  return d;
};

export const calculateBoschDate = (d: Date) => {
  let temp = new Date(d);
  const day = temp.getDay();
  // Perşembe (4) ve Cuma (5) -> PERŞEMBE günü tahsil edilir.
  // Cmt (6), Paz (0), Pzt (1), Sal (2), Çar (3) -> PAZARTESİ günü tahsil edilir.
  if (day === 4) { /* stays Thursday */ } 
  else if (day === 5) { temp.setDate(temp.getDate() - 1); } 
  else if (day === 6) { temp.setDate(temp.getDate() + 2); } 
  else if (day === 0) { temp.setDate(temp.getDate() + 1); } 
  else if (day === 1) { /* stays Monday */ } 
  else if (day === 2) { temp.setDate(temp.getDate() - 1); } 
  else if (day === 3) { temp.setDate(temp.getDate() - 2); } 
  return temp;
};

export const generateRecurringTransactions = (rules: RecurringRule[], start: Date, end: Date): Transaction[] => {
  const generated: Transaction[] = [];
  rules.forEach(rule => {
    const ruleStartDate = new Date(rule.startDate);
    const loopStart = new Date(Math.max(start.getTime(), ruleStartDate.getTime()));
    let d = new Date(loopStart);

    while (d <= end) {
      let isMatch = false;
      if (rule.freq === 'weekly' && rule.weekDays) {
        if (rule.weekDays.includes(d.getDay())) isMatch = true;
      } else if (rule.freq === 'monthly') {
        if (rule.monthType === 'fixed' && rule.fixedDay) {
          const lastDayOfMonth = new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
          const targetDay = Math.min(rule.fixedDay, lastDayOfMonth);
          if (d.getDate() === targetDay) isMatch = true;
        } else if (rule.monthType === 'special' && rule.specialDay && rule.specialOrd) {
          const desiredDay = parseInt(rule.specialDay);
          const ord = parseInt(rule.specialOrd);
          let targetDate: Date | null = null;

          if (ord === 5) { // Last
            const lastDate = new Date(d.getFullYear(), d.getMonth() + 1, 0);
            for (let k = 0; k < 7; k++) {
              let temp = new Date(lastDate);
              temp.setDate(temp.getDate() - k);
              if (temp.getDay() === desiredDay) { targetDate = temp; break; }
            }
          } else {
            let count = 0;
            for (let k = 1; k <= 31; k++) {
              let temp = new Date(d.getFullYear(), d.getMonth(), k);
              if (temp.getMonth() !== d.getMonth()) break;
              if (temp.getDay() === desiredDay) {
                count++;
                if (count === ord) { targetDate = temp; break; }
              }
            }
          }
          if (targetDate && targetDate.getDate() === d.getDate()) isMatch = true;
        }
      }

      if (isMatch) {
        generated.push({
          id: `rec-${rule.id}-${toLocalYMD(d)}`,
          date: toLocalYMD(d),
          desc: rule.desc,
          amount: rule.amount,
          type: rule.type,
          currency: 'TL'
        });
      }
      d.setDate(d.getDate() + 1);
    }
  });
  return generated;
};

export const calculateFlow = (
  projectionType: ProjectionType,
  assets: Asset[],
  checks: Check[],
  manualTransactions: Transaction[],
  recurringRules: RecurringRule[],
  eurRate: number,
  viewCurrency: Currency
): FlowPeriod[] => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const periods: FlowPeriod[] = [];
  let startDate = new Date(today);
  let endDate = new Date(today);

  if (projectionType === 'daily') {
    endDate.setDate(today.getDate() + 45);
    for (let i = 0; i < 45; i++) {
      let d = new Date(today);
      d.setDate(today.getDate() + i);
      periods.push({
        start: new Date(d),
        end: new Date(d),
        label: d.toLocaleDateString('tr-TR', { day: '2-digit', month: '2-digit', weekday: 'short' }),
        incomes: 0,
        expenses: 0,
        balance: 0,
        details: {}
      });
    }
  } else if (projectionType === 'weekly') {
    endDate.setDate(today.getDate() + (12 * 7));
    let current = new Date(today);
    for (let i = 0; i < 12; i++) {
      let weekEnd = new Date(current);
      // End of week (Friday or Sunday based on preference, let's go Sunday)
      const day = current.getDay();
      const diff = 7 - (day === 0 ? 7 : day);
      weekEnd.setDate(current.getDate() + diff);
      periods.push({
        start: new Date(current),
        end: new Date(weekEnd),
        label: `${toLocalYMD(current)} / ${toLocalYMD(weekEnd)}`,
        incomes: 0,
        expenses: 0,
        balance: 0,
        details: {}
      });
      current = new Date(weekEnd);
      current.setDate(current.getDate() + 1);
    }
  } else {
    endDate.setMonth(today.getMonth() + 6);
    let current = new Date(today);
    for (let i = 0; i < 6; i++) {
      let monthEnd = new Date(current.getFullYear(), current.getMonth() + 1, 0);
      periods.push({
        start: new Date(current),
        end: new Date(monthEnd),
        label: current.toLocaleString('tr-TR', { month: 'long', year: 'numeric' }),
        incomes: 0,
        expenses: 0,
        balance: 0,
        details: {}
      });
      current = new Date(monthEnd);
      current.setDate(current.getDate() + 1);
    }
  }

  // Initial balance from assets
  let initialBalance = 0;
  assets.filter(a => a.included).forEach(a => {
    let amt = a.amount;
    if (viewCurrency === 'TL' && a.currency === 'EUR') amt *= eurRate;
    else if (viewCurrency === 'EUR' && a.currency === 'TL') amt /= eurRate;
    initialBalance += amt;
  });

  // All Transactions
  const allTrans: Transaction[] = [...manualTransactions];
  checks.forEach(c => allTrans.push({
    id: c.id,
    date: c.effectiveDateStr,
    desc: `ÇEK: ${c.desc}`,
    amount: c.amount,
    type: 'income',
    currency: 'TL'
  }));
  allTrans.push(...generateRecurringTransactions(recurringRules, today, endDate));

  let runningBalance = initialBalance;
  periods.forEach(p => {
    const periodTrans = allTrans.filter(t => {
      const d = new Date(t.date);
      return d >= p.start && d <= p.end;
    });

    periodTrans.forEach(t => {
      let val = t.amount;
      if (viewCurrency === 'TL' && t.currency === 'EUR') val *= eurRate;
      else if (viewCurrency === 'EUR' && t.currency === 'TL') val /= eurRate;

      if (t.type === 'income') {
        p.incomes += val;
      } else {
        p.expenses += val;
      }
      p.details[t.desc] = (p.details[t.desc] || 0) + (t.type === 'income' ? val : -val);
    });

    runningBalance += (p.incomes - p.expenses);
    p.balance = runningBalance;
  });

  return periods;
};

import { GoogleGenAI } from "@google/genai";
import { FlowPeriod } from "../types";

export const analyzeCashFlow = async (periods: FlowPeriod[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  // Prepare a brief summary of the flow for AI
  const summary = periods.map(p => ({
    date: p.label,
    in: p.incomes.toFixed(2),
    out: p.expenses.toFixed(2),
    balance: p.balance.toFixed(2)
  })).slice(0, 30); // Last 30 points

  const prompt = `
    Aşağıdaki nakit akışı verilerini analiz et ve bir yönetici özeti çıkar:
    - Kritik bakiye düşüşleri var mı?
    - En çok harcama veya gelir hangi dönemlerde?
    - Gelecek projeksiyonuna göre finansal tavsiyeler nelerdir?

    Veriler: ${JSON.stringify(summary)}

    Lütfen profesyonel, kısa ve madde işaretli bir Türkçe yanıt dön.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Analiz sırasında bir hata oluştu. Lütfen tekrar deneyin.";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Asset, Check, RecurringRule, Transaction, CustomTab, ProjectionType, Currency, FlowPeriod } from './types';
import { calculateFlow, formatMoney } from './utils/calculations';
import { analyzeCashFlow } from './services/geminiService';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Legend
} from 'recharts';

// Sub-components
import Sidebar from './components/Sidebar';
import FlowDashboard from './components/FlowDashboard';
import AssetManager from './components/AssetManager';
import CheckManager from './components/CheckManager';
import RecurringManager from './components/RecurringManager';
import ManualManager from './components/ManualManager';
import ExcelTabs from './components/ExcelTabs';

const App: React.FC = () => {
  // State
  const [activeTab, setActiveTab] = useState('flow');
  const [eurRate, setEurRate] = useState(36.50);
  const [viewCurrency, setViewCurrency] = useState<Currency>('TL');
  const [projectionType, setProjectionType] = useState<ProjectionType>('daily');

  const [assets, setAssets] = useState<Asset[]>([]);
  const [checks, setChecks] = useState<Check[]>([]);
  const [manualTransactions, setManualTransactions] = useState<Transaction[]>([]);
  const [recurringRules, setRecurringRules] = useState<RecurringRule[]>([]);
  const [customTabs, setCustomTabs] = useState<CustomTab[]>([]);

  // Local Storage Sync
  useEffect(() => {
    const savedAssets = localStorage.getItem('cashflow_assets');
    const savedChecks = localStorage.getItem('cashflow_checks');
    const savedManual = localStorage.getItem('cashflow_manual');
    const savedRules = localStorage.getItem('cashflow_rules');
    const savedTabs = localStorage.getItem('cashflow_tabs');

    if (savedAssets) setAssets(JSON.parse(savedAssets));
    if (savedChecks) setChecks(JSON.parse(savedChecks));
    if (savedManual) setManualTransactions(JSON.parse(savedManual));
    if (savedRules) setRecurringRules(JSON.parse(savedRules));
    if (savedTabs) setCustomTabs(JSON.parse(savedTabs));

    fetchEurRate();
  }, []);

  useEffect(() => {
    localStorage.setItem('cashflow_assets', JSON.stringify(assets));
    localStorage.setItem('cashflow_checks', JSON.stringify(checks));
    localStorage.setItem('cashflow_manual', JSON.stringify(manualTransactions));
    localStorage.setItem('cashflow_rules', JSON.stringify(recurringRules));
    localStorage.setItem('cashflow_tabs', JSON.stringify(customTabs));
  }, [assets, checks, manualTransactions, recurringRules, customTabs]);

  const fetchEurRate = async () => {
    try {
      const response = await fetch('https://api.frankfurter.app/latest?from=EUR&to=TRY');
      if (response.ok) {
        const data = await response.json();
        setEurRate(data.rates.TRY);
      }
    } catch (e) { console.error("Rate fetch failed", e); }
  };

  const periods = useMemo(() => 
    calculateFlow(projectionType, assets, checks, manualTransactions, recurringRules, eurRate, viewCurrency),
    [projectionType, assets, checks, manualTransactions, recurringRules, eurRate, viewCurrency]
  );

  return (
    <div className="flex min-h-screen bg-slate-50">
      {/* Sidebar */}
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        customTabs={customTabs}
        setCustomTabs={setCustomTabs}
      />

      {/* Main Content */}
      <main className="flex-1 p-4 lg:p-8 overflow-y-auto">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">Nakit Akışı Yönetimi</h1>
            <p className="text-slate-500">Finansal projeksiyonunuzu anlık olarak takip edin.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3 bg-white p-2 rounded-xl shadow-sm border">
            <div className="flex items-center gap-2 px-3 border-r pr-4">
              <span className="text-xs font-semibold text-slate-500">1 EUR =</span>
              <input 
                type="number" 
                value={eurRate} 
                onChange={(e) => setEurRate(Number(e.target.value))}
                className="w-16 text-sm font-bold bg-transparent outline-none border-b border-slate-200 focus:border-blue-500"
              />
              <span className="text-xs font-semibold text-slate-500">TL</span>
            </div>

            <div className="flex bg-slate-100 p-1 rounded-lg">
              <button 
                onClick={() => setViewCurrency('TL')}
                className={`px-3 py-1 rounded-md text-xs font-bold transition-all ${viewCurrency === 'TL' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
              >
                TL
              </button>
              <button 
                onClick={() => setViewCurrency('EUR')}
                className={`px-3 py-1 rounded-md text-xs font-bold transition-all ${viewCurrency === 'EUR' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
              >
                EUR
              </button>
            </div>
          </div>
        </header>

        <div className="space-y-6">
          {activeTab === 'flow' && (
            <FlowDashboard 
              periods={periods} 
              projectionType={projectionType} 
              setProjectionType={setProjectionType}
              viewCurrency={viewCurrency}
              assets={assets}
              setAssets={setAssets}
              eurRate={eurRate}
            />
          )}

          {activeTab === 'assets' && (
            <AssetManager assets={assets} setAssets={setAssets} viewCurrency={viewCurrency} eurRate={eurRate} />
          )}

          {activeTab === 'checks' && (
            <CheckManager checks={checks} setChecks={setChecks} />
          )}

          {activeTab === 'recurring' && (
            <RecurringManager rules={recurringRules} setRules={setRecurringRules} />
          )}

          {activeTab === 'manual' && (
            <ManualManager transactions={manualTransactions} setTransactions={setManualTransactions} />
          )}

          {activeTab.startsWith('cust-') && (
            <ExcelTabs 
              tabId={activeTab} 
              transactions={manualTransactions} 
              setTransactions={setManualTransactions} 
              customTabs={customTabs}
              setCustomTabs={setCustomTabs}
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { CustomTab } from '../types';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (id: string) => void;
  customTabs: CustomTab[];
  setCustomTabs: React.Dispatch<React.SetStateAction<CustomTab[]>>;
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab, customTabs, setCustomTabs }) => {
  const menuItems = [
    { id: 'flow', label: 'Nakit Akışı', icon: 'fa-chart-line' },
    { id: 'assets', label: 'Varlıklar', icon: 'fa-vault' },
    { id: 'checks', label: 'Çekler', icon: 'fa-money-check-dollar' },
    { id: 'recurring', label: 'Tekrarlı İşlemler', icon: 'fa-rotate' },
    { id: 'manual', label: 'Manuel İşlemler', icon: 'fa-keyboard' },
  ];

  const handleAddTab = () => {
    const name = prompt("Müşteri/Proje Adı Giriniz:", "Yeni Müşteri");
    if (!name) return;
    const newTab = { id: `cust-${Date.now()}`, name };
    setCustomTabs([...customTabs, newTab]);
    setActiveTab(newTab.id);
  };

  return (
    <div className="hidden lg:flex flex-col w-64 bg-white border-r h-screen sticky top-0">
      <div className="p-6 border-b flex items-center gap-3">
        <div className="bg-blue-600 p-2 rounded-lg">
          <i className="fa-solid fa-chart-pie text-white"></i>
        </div>
        <span className="font-bold text-lg tracking-tight">FinFlow Pro</span>
      </div>

      <nav className="flex-1 p-4 space-y-1">
        <p className="px-3 py-2 text-xs font-bold text-slate-400 uppercase tracking-widest">Genel</p>
        {menuItems.map(item => (
          <button
            key={item.id}
            onClick={() => setActiveTab(item.id)}
            className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all font-medium ${
              activeTab === item.id 
              ? 'bg-blue-50 text-blue-700 shadow-sm' 
              : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
            }`}
          >
            <i className={`fa-solid ${item.icon} w-5 text-center`}></i>
            {item.label}
          </button>
        ))}

        <div className="pt-6">
          <div className="flex items-center justify-between px-3 py-2">
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Özel Takip</p>
            <button 
              onClick={handleAddTab}
              className="text-blue-600 hover:text-blue-800 text-xs font-bold"
            >
              <i className="fa-solid fa-plus"></i>
            </button>
          </div>
          {customTabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all font-medium mb-1 ${
                activeTab === tab.id 
                ? 'bg-blue-50 text-blue-700 shadow-sm' 
                : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
              }`}
            >
              <i className="fa-solid fa-folder-open w-5 text-center"></i>
              <span className="truncate">{tab.name}</span>
            </button>
          ))}
        </div>
      </nav>

      <div className="p-4 border-top">
        <div className="bg-slate-900 rounded-2xl p-4 text-white">
          <p className="text-xs font-semibold opacity-70 mb-1">Versiyon</p>
          <p className="text-sm font-bold">Online v3.0 React</p>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { FlowPeriod, ProjectionType, Currency, Asset } from '../types';
import { formatMoney } from '../utils/calculations';
import { analyzeCashFlow } from '../services/geminiService';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';

interface FlowDashboardProps {
  periods: FlowPeriod[];
  projectionType: ProjectionType;
  setProjectionType: (t: ProjectionType) => void;
  viewCurrency: Currency;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  eurRate: number;
}

const FlowDashboard: React.FC<FlowDashboardProps> = ({ 
  periods, projectionType, setProjectionType, viewCurrency, assets, setAssets, eurRate 
}) => {
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [selectedDetails, setSelectedDetails] = useState<FlowPeriod | null>(null);

  const handleAiAnalysis = async () => {
    setLoadingAi(true);
    const analysis = await analyzeCashFlow(periods);
    setAiInsight(analysis);
    setLoadingAi(false);
  };

  const toggleAsset = (id: string) => {
    setAssets(prev => prev.map(a => a.id === id ? { ...a, included: !a.included } : a));
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Sidebar Controls */}
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-2xl border shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <i className="fa-solid fa-sliders text-blue-600"></i> Projeksiyon
            </h3>
            <div className="grid grid-cols-3 gap-1 bg-slate-100 p-1 rounded-xl">
              {(['daily', 'weekly', 'monthly'] as ProjectionType[]).map(type => (
                <button
                  key={type}
                  onClick={() => setProjectionType(type)}
                  className={`py-2 rounded-lg text-xs font-bold capitalize transition-all ${
                    projectionType === type ? 'bg-white shadow text-blue-700' : 'text-slate-500 hover:text-slate-800'
                  }`}
                >
                  {type === 'daily' ? 'Günlük' : type === 'weekly' ? 'Haftalık' : 'Aylık'}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white p-5 rounded-2xl border shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <i className="fa-solid fa-vault text-blue-600"></i> Aktif Varlıklar
            </h3>
            <div className="space-y-2 max-h-60 overflow-y-auto custom-scrollbar">
              {assets.map(asset => (
                <label key={asset.id} className="flex items-center justify-between p-2 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors border border-transparent hover:border-slate-100">
                  <div className="flex items-center gap-3">
                    <input 
                      type="checkbox" 
                      checked={asset.included} 
                      onChange={() => toggleAsset(asset.id)}
                      className="w-4 h-4 text-blue-600 rounded"
                    />
                    <div className="flex flex-col">
                      <span className="text-sm font-semibold text-slate-700 truncate max-w-[120px]">{asset.name}</span>
                      <span className="text-[10px] text-slate-400 uppercase">{asset.subType}</span>
                    </div>
                  </div>
                  <span className="text-xs font-bold text-slate-600">
                    {formatMoney(asset.amount, asset.currency)}
                  </span>
                </label>
              ))}
