    Veriler: ${JSON.stringify(summary)}

    Lütfen profesyonel, kısa ve madde işaretli bir Türkçe yanıt dön.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return { text: response.text };
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return { text: "Analiz sırasında bir hata oluştu." };
  }
};

export const fetchMarketInsights = async () => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = "Türkiye güncel ekonomi gündemi, döviz kuru beklentileri ve enflasyon verileri hakkında kısa bir özet ver.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title,
      uri: chunk.web?.uri
    })).filter((s: any) => s.title && s.uri) || [];

    return {
      text: response.text,
      sources: sources
    };
  } catch (error) {
    console.error("Market Insights Error:", error);
    return { text: "Haberler alınamadı.", sources: [] };
  }
};

export const chatWithAssistant = async (userMessage: string, context: { assets: Asset[], periods: FlowPeriod[] }) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const systemPrompt = `
    Sen "FinFlow Pro" adlı finansal yönetim uygulamasının AI asistanısın. 
    Kullanıcının varlıklarını ve nakit akışı verilerini görebiliyorsun.

    Kullanıcı Verileri:
    Varlıklar: ${JSON.stringify(context.assets.map(a => ({ name: a.name, amount: a.amount, currency: a.currency })))}
    Projeksiyon Özeti: ${JSON.stringify(context.periods.map(p => ({ period: p.label, balance: p.balance })).slice(0, 10))}

    Kullanıcının sorularına bu verilere dayanarak kısa, profesyonel ve yardımcı yanıtlar ver. 
    Finansal tavsiye değil, veri analizi sun.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userMessage,
      config: {
        systemInstruction: systemPrompt
      }
    });
    return response.text;
  } catch (error) {
    return "Şu an yanıt veremiyorum, lütfen sonra tekrar deneyin.";
  }
};

