            <tbody className="divide-y divide-slate-100">
              {periods.map((p, idx) => (
                <tr key={idx} className={`hover:bg-slate-50 transition-colors ${p.start.getDay() === 0 || p.start.getDay() === 6 ? 'bg-slate-50/30' : ''}`}>
                  <td className="p-4 text-sm font-medium text-slate-600">{p.label}</td>
                  <td className="p-4 text-sm font-bold text-green-600 text-right">
                    {p.incomes > 0 ? formatMoney(p.incomes, viewCurrency) : '-'}
                  </td>
                  <td className="p-4 text-sm font-bold text-rose-600 text-right">
                    {p.expenses > 0 ? formatMoney(p.expenses, viewCurrency) : '-'}
                  </td>
                  <td className="p-4 text-sm font-black text-slate-800 text-right">
                    <span className={p.balance < 0 ? 'text-rose-600' : ''}>
                      {formatMoney(p.balance, viewCurrency)}
                    </span>
                  </td>
                  <td className="p-4 text-center">
                    {Object.keys(p.details).length > 0 && (
                      <button 
                        onClick={() => setSelectedDetails(p)}
                        className="text-[10px] font-black uppercase text-blue-600 hover:bg-blue-100 px-3 py-1.5 rounded-lg border border-blue-200 transition-all"
                      >
                        İncele
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Details Modal */}
      {selectedDetails && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="bg-blue-600 p-6 text-white flex justify-between items-center shadow-lg">
              <div>
                <h4 className="font-bold text-lg">Dönem İçi İşlemler</h4>
                <p className="text-xs text-blue-100 opacity-80 font-medium">{selectedDetails.label}</p>
              </div>
              <button onClick={() => setSelectedDetails(null)} className="p-2 hover:bg-blue-500 rounded-full transition-colors">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="p-6">
              <div className="space-y-4 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
                {(Object.entries(selectedDetails.details) as [string, number][]).map(([desc, amount], idx) => (
                  <div key={idx} className="flex justify-between items-center border-b border-slate-50 pb-3 last:border-0 hover:bg-slate-50 p-1 rounded-lg transition-colors">
                    <span className="text-sm font-medium text-slate-600">{desc}</span>
                    <span className={`text-sm font-bold ${amount >= 0 ? 'text-green-600' : 'text-rose-600'}`}>
                      {amount >= 0 ? '+' : ''}{formatMoney(amount, viewCurrency)}
                    </span>
                  </div>
                ))}
              </div>
              <div className="mt-6 pt-6 border-t flex justify-between items-center">
                <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Periyot Sonu Bakiye</span>
                <span className={`text-xl font-black ${selectedDetails.balance < 0 ? 'text-rose-600' : 'text-slate-800'}`}>
                  {formatMoney(selectedDetails.balance, viewCurrency)}
                </span>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FlowDashboard;

import React, { useState } from 'react';
import { RecurringRule } from '../types';
import { formatMoney } from '../utils/calculations';

interface RecurringManagerProps {
  rules: RecurringRule[];
  setRules: React.Dispatch<React.SetStateAction<RecurringRule[]>>;
}

const RecurringManager: React.FC<RecurringManagerProps> = ({ rules, setRules }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState<Partial<RecurringRule>>({
    type: 'expense',
    startDate: '',
    amount: 0,
    desc: '',
    freq: 'monthly',
    weekDays: [],
    monthType: 'fixed',
    fixedDay: 1,
    specialOrd: '1',
    specialDay: '1'
  });

  const getRuleDescription = (r: RecurringRule) => {
    if (r.freq === 'weekly') {
      const days = ['Pzt', 'Sal', 'Çar', 'Per', 'Cum', 'Cmt', 'Paz'];
      const activeDays = r.weekDays?.map(d => days[d - 1]).join(', ');
      return `Her hafta ${activeDays || '-'} günleri`;
    }
    if (r.monthType === 'fixed') {
      return `Her ayın ${r.fixedDay}. günü`;
    }
    const ords: any = { '1': '1.', '2': '2.', '3': '3.', '4': '4.', '5': 'Son' };
    const days: any = { '1': 'Pazartesi', '2': 'Salı', '3': 'Çarşamba', '4': 'Perşembe', '5': 'Cuma' };
    return `Her ayın ${ords[r.specialOrd || '1']} ${days[r.specialDay || '1']} günü`;
  };

  const handleSave = () => {
    if (!form.startDate || !form.amount || !form.desc) {
      alert("Lütfen zorunlu alanları doldurun.");
      return;
    }

    const ruleData = {
      type: form.type as any,
      startDate: form.startDate,
      amount: form.amount,
      desc: form.desc,
      freq: form.freq as any,
      weekDays: form.weekDays,
      monthType: form.monthType as any,
      fixedDay: form.fixedDay,
      specialOrd: form.specialOrd,
      specialDay: form.specialDay
    };

    if (editingId) {
      setRules(rules.map(r => r.id === editingId ? { ...r, ...ruleData } : r));
      setEditingId(null);
    } else {
      const newRule: RecurringRule = {
        id: Date.now().toString(),
        ...ruleData
      };
      setRules([...rules, newRule]);
    }
    resetForm();
  };

  const resetForm = () => {
    setForm({
      type: 'expense',
      startDate: '',
      amount: 0,
      desc: '',
      freq: 'monthly',
      weekDays: [],
      monthType: 'fixed',
      fixedDay: 1,
      specialOrd: '1',
      specialDay: '1'
    });
    setEditingId(null);
  };

  const editRule = (r: RecurringRule) => {
    setEditingId(r.id);
    setForm({
      type: r.type,
      startDate: r.startDate,
      amount: r.amount,
      desc: r.desc,
      freq: r.freq,
      weekDays: r.weekDays || [],
      monthType: r.monthType,
      fixedDay: r.fixedDay,
      specialOrd: r.specialOrd || '1',
      specialDay: r.specialDay || '1'
    });
  };

  const deleteRule = (id: string) => {
    if (confirm("Bu kuralı silmek istediğinize emin misiniz?")) {
      setRules(rules.filter(r => r.id !== id));
      if (editingId === id) resetForm();
    }
  };

  const toggleDay = (day: number) => {
    const current = form.weekDays || [];
    if (current.includes(day)) setForm({...form, weekDays: current.filter(d => d !== day)});
    else setForm({...form, weekDays: [...current, day]});
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      <div className="bg-white p-6 rounded-2xl border shadow-sm h-fit">
        <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
           <i className="fa-solid fa-rotate text-amber-500"></i> {editingId ? 'Kuralı Düzenle' : 'Yeni Tekrarlı Kural'}
        </h3>
        <div className="space-y-4">
          <div className="flex bg-slate-100 p-1 rounded-xl">
             <button 
                onClick={() => setForm({...form, type: 'income'})}
                className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${form.type === 'income' ? 'bg-white shadow text-green-600' : 'text-slate-500'}`}
             >GELİR</button>
             <button 
                onClick={() => setForm({...form, type: 'expense'})}
                className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${form.type === 'expense' ? 'bg-white shadow text-rose-600' : 'text-slate-500'}`}
             >GİDER</button>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">Başlangıç</label>
              <input 
                type="date"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500"
                value={form.startDate}
                onChange={e => setForm({...form, startDate: e.target.value})}
              />
            </div>
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">Tutar (TL)</label>
              <input 
                type="number"
                className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500"
                value={form.amount || ''}
                onChange={e => setForm({...form, amount: parseFloat(e.target.value) || 0})}
              />
            </div>
          </div>
          <div>
            <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">Açıklama</label>
            <input 
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="Kira, Maaş, Düzenli Ödeme..."
              value={form.desc}
              onChange={e => setForm({...form, desc: e.target.value})}
            />
          </div>
          <div>
            <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">Tekrar Sıklığı</label>
            <select 
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500"
              value={form.freq}
              onChange={e => setForm({...form, freq: e.target.value as any})}
            >
              <option value="weekly">Haftalık</option>
              <option value="monthly">Aylık</option>
            </select>
          </div>

          {form.freq === 'weekly' && (
            <div className="bg-slate-50 p-3 rounded-xl border border-slate-200">
               <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block">Hangi Günler?</label>
               <div className="flex flex-wrap gap-2">
                  {['Pzt', 'Sal', 'Çar', 'Per', 'Cum', 'Cmt', 'Paz'].map((label, idx) => (
                    <button
                      key={idx}
                      type="button"
                      onClick={() => toggleDay(idx + 1)}
                      className={`w-9 h-9 rounded-lg text-xs font-bold border transition-all ${
                        (form.weekDays || []).includes(idx + 1) ? 'bg-blue-600 text-white border-blue-600 shadow' : 'bg-white text-slate-500'
                      }`}
                    >{label}</button>
                  ))}
               </div>
            </div>
          )}

          {form.freq === 'monthly' && (
            <div className="bg-slate-50 p-3 rounded-xl border border-slate-200 space-y-3">
               <div className="flex gap-4">
                  <label className="flex items-center gap-2 cursor-pointer">
                    <input type="radio" checked={form.monthType === 'fixed'} onChange={() => setForm({...form, monthType: 'fixed'})} />
                    <span className="text-xs font-bold text-slate-600">Belirli Gün</span>
                  </label>
                  <label className="flex items-center gap-2 cursor-pointer">
                    <input type="radio" checked={form.monthType === 'special'} onChange={() => setForm({...form, monthType: 'special'})} />
                    <span className="text-xs font-bold text-slate-600">Özel Gün</span>
                  </label>
               </div>
               {form.monthType === 'fixed' ? (
                 <input 
                    type="number" 
                    min="1" max="31" 
                    placeholder="Gün (1-31)" 
                    className="w-full bg-white border border-slate-200 rounded-lg p-2 text-sm outline-none" 
                    value={form.fixedDay || ''}
                    onChange={e => setForm({...form, fixedDay: parseInt(e.target.value) || 1})}
                  />
               ) : (
                 <div className="flex gap-2">
                    <select 
                      className="flex-1 bg-white border border-slate-200 rounded-lg p-2 text-sm outline-none"
                      value={form.specialOrd}
                      onChange={e => setForm({...form, specialOrd: e.target.value})}
                    >
                      <option value="1">1.</option><option value="2">2.</option><option value="3">3.</option><option value="4">4.</option><option value="5">Son</option>
                    </select>
                    <select 
                      className="flex-1 bg-white border border-slate-200 rounded-lg p-2 text-sm outline-none"
                      value={form.specialDay}
                      onChange={e => setForm({...form, specialDay: e.target.value})}
                    >
                      <option value="1">Pazartesi</option><option value="2">Salı</option><option value="3">Çarşamba</option><option value="4">Perşembe</option><option value="5">Cuma</option>
                    </select>
                 </div>
               )}
            </div>
          )}

          <div className="flex gap-2">
            <button 
              onClick={handleSave}
              className={`flex-1 ${editingId ? 'bg-indigo-600' : 'bg-amber-500'} text-white font-bold p-4 rounded-xl hover:opacity-90 shadow-lg transition-all`}
            >
              {editingId ? 'Güncelle' : 'Kuralı Kaydet'}
            </button>
            {editingId && (
              <button onClick={resetForm} className="bg-slate-100 text-slate-600 font-bold p-4 rounded-xl hover:bg-slate-200 transition-all">
                Vazgeç
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
          <div className="p-5 border-b flex justify-between items-center bg-slate-50/50">
            <h3 className="font-bold text-slate-800 text-lg">Aktif Tekrarlı Kurallar</h3>
            <span className="text-xs font-bold bg-white border text-amber-600 px-3 py-1 rounded-full">{rules.length} Kural</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b">
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Tip</th>
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Açıklama</th>
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Kural Detayı</th>
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Tutar</th>
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-center">İşlem</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {rules.map(r => (
                  <tr key={r.id} className={`hover:bg-slate-50 transition-colors ${editingId === r.id ? 'bg-blue-50' : ''}`}>
                    <td className="p-4 text-sm font-bold">
                       <span className={`px-2 py-1 rounded text-[10px] uppercase tracking-wider ${r.type === 'income' ? 'bg-green-100 text-green-700' : 'bg-rose-100 text-rose-700'}`}>
                         {r.type === 'income' ? 'Gelir' : 'Gider'}
                       </span>
                    </td>
                    <td className="p-4 text-sm font-medium text-slate-700">{r.desc}</td>
                    <td className="p-4 text-xs text-slate-500 font-medium">
                      {getRuleDescription(r)}
                    </td>
                    <td className="p-4 text-sm font-black text-slate-800 text-right">{formatMoney(r.amount)}</td>
                    <td className="p-4 text-center">
                      <div className="flex justify-center gap-1">
                        <button onClick={() => editRule(r)} className="text-blue-500 hover:bg-blue-50 p-2 rounded-lg transition-colors" title="Düzenle">
                          <i className="fa-solid fa-pencil"></i>
                        </button>
                        <button onClick={() => deleteRule(r.id)} className="text-rose-500 hover:bg-rose-50 p-2 rounded-lg transition-colors" title="Sil">
                          <i className="fa-solid fa-trash-can"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
                {rules.length === 0 && (
                  <tr>
                    <td colSpan={5} className="p-16 text-center text-slate-400 italic">Henüz tanımlı bir kural bulunmuyor.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RecurringManager;

import React, { useState, useMemo } from 'react';
import { FlowPeriod, ProjectionType, Currency, Asset } from '../types';
import { formatMoney } from '../utils/calculations';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';

interface FlowDashboardProps {
  periods: FlowPeriod[];
  projectionType: ProjectionType;
  setProjectionType: (t: ProjectionType) => void;
  viewCurrency: Currency;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  eurRate: number;
}

const FlowDashboard: React.FC<FlowDashboardProps> = ({ 
  periods, projectionType, setProjectionType, viewCurrency, assets, setAssets, eurRate 
}) => {
  const [selectedDetails, setSelectedDetails] = useState<FlowPeriod | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const toggleAsset = (id: string) => {
    setAssets(prev => prev.map(a => a.id === id ? { ...a, included: !a.included } : a));
  };

  const filteredPeriods = useMemo(() => {
    if (!searchQuery.trim()) return periods;
    const query = searchQuery.toLowerCase();
    return periods.map(p => {
      // Periyodun detaylarında arama yap
      const filteredDetails: Record<string, number> = {};
      let hasMatch = p.label.toLowerCase().includes(query);

      Object.entries(p.details).forEach(([desc, amount]) => {
        if (desc.toLowerCase().includes(query)) {
          filteredDetails[desc] = amount;
          hasMatch = true;
        }
      });

      if (hasMatch) {
        return { ...p, details: Object.keys(filteredDetails).length > 0 ? filteredDetails : p.details };
      }
      return null;
    }).filter(p => p !== null) as FlowPeriod[];
  }, [periods, searchQuery]);

  // Grafik verisi (Daima tam liste kullanılır, sadece bakiye değişimi izlenir)
  const chartData = useMemo(() => {
    return periods.map(p => ({
      label: p.label,
      balance: parseFloat(p.balance.toFixed(2))
    }));
  }, [periods]);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Sidebar Controls */}
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-2xl border shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <i className="fa-solid fa-sliders text-blue-600"></i> Projeksiyon
            </h3>
            <div className="grid grid-cols-3 gap-1 bg-slate-100 p-1 rounded-xl">
              {(['daily', 'weekly', 'monthly'] as ProjectionType[]).map(type => (
                <button
                  key={type}
                  onClick={() => setProjectionType(type)}
                  className={`py-2 rounded-lg text-[10px] font-black uppercase transition-all ${
                    projectionType === type ? 'bg-white shadow text-blue-700' : 'text-slate-400 hover:text-slate-800'
                  }`}
                >
                  {type === 'daily' ? 'Günlük' : type === 'weekly' ? 'Haftalık' : 'Aylık'}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white p-5 rounded-2xl border shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <i className="fa-solid fa-vault text-blue-600"></i> Aktif Varlıklar
            </h3>
            <div className="space-y-2 max-h-60 overflow-y-auto custom-scrollbar">
              {(assets || []).map(asset => (
                <label key={asset.id} className="flex items-center justify-between p-2 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors border border-transparent hover:border-slate-100">
                  <div className="flex items-center gap-3">
                    <input 
                      type="checkbox" 
                      checked={asset.included} 
                      onChange={() => toggleAsset(asset.id)}
                      className="w-4 h-4 text-blue-600 rounded"
                    />
                    <div className="flex flex-col">
                      <span className="text-sm font-semibold text-slate-700 truncate max-w-[120px]">{asset.name}</span>
                      <span className="text-[10px] text-slate-400 uppercase">{asset.subType}</span>
                    </div>
                  </div>
                  <span className="text-xs font-bold text-slate-600">
                    {formatMoney(asset.amount, asset.currency)}
                  </span>
                </label>
              ))}
              {(!assets || assets.length === 0) && <p className="text-xs text-slate-400 italic">Varlık tanımlanmamış.</p>}
            </div>
            <div className="mt-4 pt-4 border-t flex justify-between items-center">
              <span className="text-xs font-bold text-slate-400">Başlangıç Bakiyesi:</span>
              <span className="text-lg font-black text-blue-700">
                {formatMoney(periods[0]?.balance || 0, viewCurrency)}
              </span>
            </div>
          </div>
        </div>

        {/* Chart Area */}
        <div className="lg:col-span-3">
          <div className="bg-white p-6 rounded-2xl border shadow-sm h-[450px] flex flex-col overflow-hidden">
            <div className="flex items-center justify-between mb-6">
              <h3 className="font-bold text-slate-800 text-lg">Bakiye Projeksiyon Grafiği</h3>
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full bg-blue-500"></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Net Bakiye ({viewCurrency})</span>
                </div>
              </div>
            </div>
            <div className="flex-1 w-full relative">
              <div className="absolute inset-0">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorBalance" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.2}/>
                        <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis 
                      dataKey="label" 
                      tick={{fontSize: 9, fill: '#94a3b8'}} 
                      axisLine={false} 
                      tickLine={false} 
                      interval={projectionType === 'daily' ? 7 : 0}
                      height={40}
                    />
                    <YAxis 
                      tick={{fontSize: 10, fill: '#94a3b8'}} 
                      axisLine={false} 
                      tickLine={false} 
                      tickFormatter={(val) => val >= 1000 || val <= -1000 ? `${(val/1000).toFixed(0)}k` : val}
                      domain={['auto', 'auto']}
                    />
                    <Tooltip 
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '12px' }}
                      formatter={(val: number) => [formatMoney(val, viewCurrency), 'Net Bakiye']}
                      labelStyle={{ fontWeight: 'bold', marginBottom: '4px', color: '#1e293b' }}
                    />
                    <Area 
                      type="monotone" 
                      dataKey="balance" 
                      stroke="#3b82f6" 
                      strokeWidth={3} 
                      fillOpacity={1} 
                      fill="url(#colorBalance)" 
                      isAnimationActive={true}
                      animationDuration={800}
                    />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Detailed Table */}
      <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
        <div className="p-5 border-b flex flex-col md:flex-row md:items-center justify-between gap-4 bg-slate-50/50">
          <div>
            <h3 className="font-bold text-slate-800">Projeksiyon Veri Tablosu</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">{projectionType} Akış Planı</p>
          </div>
          <div className="relative">
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm"></i>
            <input 
              type="text" 
              placeholder="İşlem veya Tarih Ara..." 
              className="bg-white border border-slate-200 rounded-xl py-2.5 pl-11 pr-4 outline-none focus:ring-2 focus:ring-blue-500 w-full md:w-64 text-sm transition-all shadow-sm"
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
            />
          </div>
        </div>
        <div className="overflow-x-auto custom-scrollbar max-h-[600px]">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b sticky top-0 z-10 shadow-sm">
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Tarih / Dönem</th>
                <th className="p-4 text-xs font-bold text-green-600 uppercase tracking-wider text-right">Giriş (+)</th>
                <th className="p-4 text-xs font-bold text-rose-600 uppercase tracking-wider text-right">Çıkış (-)</th>
                <th className="p-4 text-xs font-bold text-slate-800 uppercase tracking-wider text-right">Bakiye</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-center">Detay</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredPeriods.map((p, idx) => (
                <tr key={idx} className={`hover:bg-slate-50 transition-colors ${p.start.getDay() === 0 || p.start.getDay() === 6 ? 'bg-slate-50/30' : ''}`}>
                  <td className="p-4 text-sm font-medium text-slate-600 whitespace-nowrap">{p.label}</td>
                  <td className="p-4 text-sm font-bold text-green-600 text-right">
                    {p.incomes > 0 ? formatMoney(p.incomes, viewCurrency) : '-'}
                  </td>
                  <td className="p-4 text-sm font-bold text-rose-600 text-right">
                    {p.expenses > 0 ? formatMoney(p.expenses, viewCurrency) : '-'}
                  </td>
                  <td className="p-4 text-sm font-black text-slate-800 text-right">
                    <span className={p.balance < 0 ? 'text-rose-600' : ''}>
                      {formatMoney(p.balance, viewCurrency)}
                    </span>
                  </td>
                  <td className="p-4 text-center">
                    {Object.keys(p.details).length > 0 && (
                      <button 
                        onClick={() => setSelectedDetails(p)}
                        className="text-[10px] font-black uppercase text-blue-600 hover:bg-blue-100 px-3 py-1.5 rounded-lg border border-blue-200 transition-all shadow-sm"
                      >
                        İncele
                      </button>
                    )}
                  </td>
                </tr>
              ))}
              {filteredPeriods.length === 0 && (
                <tr>
                  <td colSpan={5} className="p-20 text-center text-slate-400 italic">Aranan kriterlere uygun veri bulunamadı.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Details Modal */}
      {selectedDetails && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="bg-blue-600 p-6 text-white flex justify-between items-center shadow-lg">
              <div>
                <h4 className="font-bold text-lg">Dönem İçi İşlemler</h4>
                <p className="text-xs text-blue-100 opacity-80 font-medium">{selectedDetails.label}</p>
              </div>
              <button onClick={() => setSelectedDetails(null)} className="p-2 hover:bg-blue-500 rounded-full transition-colors">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="p-6">
              <div className="space-y-4 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
                {(Object.entries(selectedDetails.details) as [string, number][]).map(([desc, amount], idx) => (
                  <div key={idx} className="flex justify-between items-center border-b border-slate-50 pb-3 last:border-0 hover:bg-slate-50 p-1 rounded-lg transition-colors">
                    <span className="text-sm font-medium text-slate-600">{desc}</span>
                    <span className={`text-sm font-bold ${amount >= 0 ? 'text-green-600' : 'text-rose-600'}`}>
                      {amount >= 0 ? '+' : ''}{formatMoney(amount, viewCurrency)}
                    </span>
                  </div>
                ))}
              </div>
              <div className="mt-6 pt-6 border-t flex justify-between items-center">
                <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Periyot Sonu Bakiye</span>
                <span className={`text-xl font-black ${selectedDetails.balance < 0 ? 'text-rose-600' : 'text-slate-800'}`}>
                  {formatMoney(selectedDetails.balance, viewCurrency)}
                </span>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FlowDashboard;

import React, { useState } from 'react';
import { Transaction } from '../types';
import { formatMoney } from '../utils/calculations';

interface ManualManagerProps {
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
}

const ManualManager: React.FC<ManualManagerProps> = ({ transactions, setTransactions }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState<Partial<Transaction>>({
    type: 'expense',
    date: '',
    amount: 0,
    desc: '',
    currency: 'TL'
  });

  const handleSave = () => {
    // Tutarın sayı olduğundan emin ol
    const parsedAmount = parseFloat(form.amount?.toString() || '0');

    if (!form.date || !form.desc || isNaN(parsedAmount) || parsedAmount <= 0) {
      alert("Lütfen geçerli tarih, açıklama ve pozitif bir tutar giriniz.");
      return;
    }

    const transData: Omit<Transaction, 'id'> = {
      type: (form.type || 'expense') as 'income' | 'expense',
      date: form.date,
      amount: parsedAmount,
      desc: form.desc,
      currency: (form.currency || 'TL') as 'TL' | 'EUR',
      source: 'manual' as const
    };

    if (editingId) {
      setTransactions(prev => prev.map(t => t.id === editingId ? { ...t, ...transData } : t));
      setEditingId(null);
    } else {
      const newTrans: Transaction = {
        id: `manual-${Date.now()}`,
        ...transData
      };
      setTransactions(prev => [...prev, newTrans]);
    }
    resetForm();
  };

  const resetForm = () => {
    setForm({ type: 'expense', date: '', amount: 0, desc: '', currency: 'TL' });
    setEditingId(null);
  };

  const editTrans = (t: Transaction) => {
    setEditingId(t.id);
    setForm({
      type: t.type,
      date: t.date,
      amount: t.amount,
      desc: t.desc,
      currency: t.currency
    });
  };

  const deleteTrans = (id: string) => {
    if (confirm("Bu işlemi silmek istediğinize emin misiniz?")) {
      setTransactions(prev => prev.filter(t => t.id !== id));
      if (editingId === id) resetForm();
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      <div className="bg-white p-6 rounded-2xl border shadow-sm h-fit">
        <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
          <i className="fa-solid fa-keyboard text-slate-400"></i>
          {editingId ? 'İşlemi Düzenle' : 'Yeni Manuel İşlem'}
        </h3>
        <div className="space-y-4">
          <div className="flex bg-slate-100 p-1 rounded-xl">
             <button 
                onClick={() => setForm({...form, type: 'income'})}
                className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${form.type === 'income' ? 'bg-white shadow text-green-600' : 'text-slate-500'}`}
             >GELİR (+)</button>
             <button 
                onClick={() => setForm({...form, type: 'expense'})}
                className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${form.type === 'expense' ? 'bg-white shadow text-rose-600' : 'text-slate-500'}`}
             >GİDER (-)</button>
          </div>
          <div>
            <label className="text-xs font-bold text-slate-400 uppercase mb-2 block tracking-widest">Tarih</label>
            <input 
              type="date"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500"
              value={form.date}
              onChange={e => setForm({...form, date: e.target.value})}
            />
          </div>
          <div>
            <label className="text-xs font-bold text-slate-400 uppercase mb-2 block tracking-widest">Tutar (TL)</label>
            <input 
              type="number"
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500"
              value={form.amount || ''}
              onChange={e => setForm({...form, amount: e.target.value as any})}
              placeholder="0,00"
            />
          </div>
          <div>
            <label className="text-xs font-bold text-slate-400 uppercase mb-2 block tracking-widest">Açıklama</label>
            <input 
              className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="İşlem detayı (Firma adı vb.)"
              value={form.desc}
              onChange={e => setForm({...form, desc: e.target.value})}
            />
          </div>
          <div className="flex gap-2 pt-2">
            <button 
              onClick={handleSave}
              className={`flex-1 ${editingId ? 'bg-indigo-600' : 'bg-slate-800'} text-white font-bold p-4 rounded-xl hover:opacity-90 shadow-lg transition-all`}
            >
              {editingId ? 'Güncelle' : 'İşlemi Kaydet'}
            </button>
            {editingId && (
              <button onClick={resetForm} className="bg-slate-100 text-slate-600 font-bold p-4 rounded-xl hover:bg-slate-200 transition-all">
                İptal
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
          <div className="p-5 border-b flex justify-between items-center bg-slate-50/50">
            <h3 className="font-bold text-slate-800 text-lg">Manuel İşlemler Listesi</h3>
            <span className="text-xs font-bold bg-white border text-slate-500 px-3 py-1 rounded-full">
              {transactions.filter(t => t.source === 'manual').length} İşlem
            </span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b">
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Tarih</th>
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Açıklama</th>
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Tutar</th>
                  <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-center">İşlem</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {transactions
                  .filter(t => t.source === 'manual')
                  .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()) // Yeniden eskiye
                  .map(t => (
                  <tr key={t.id} className={`hover:bg-slate-50 transition-colors ${editingId === t.id ? 'bg-indigo-50' : ''}`}>
                    <td className="p-4 text-sm font-medium text-slate-500">{t.date}</td>
                    <td className="p-4 text-sm font-bold text-slate-700">
                      <span className={`mr-2 inline-block w-2 h-2 rounded-full ${t.type === 'income' ? 'bg-green-500' : 'bg-rose-500'}`}></span>
                      {t.desc}
                    </td>
                    <td className="p-4 text-sm font-black text-slate-800 text-right">
                      <span className={t.type === 'income' ? 'text-green-600' : 'text-rose-600'}>
                        {t.type === 'income' ? '+' : '-'}{formatMoney(t.amount)}
                      </span>
                    </td>
                    <td className="p-4 text-center">
                      <div className="flex justify-center gap-1">
                        <button onClick={() => editTrans(t)} className="text-blue-500 hover:bg-blue-50 p-2 rounded-lg transition-colors" title="Düzenle">
                          <i className="fa-solid fa-pencil"></i>
                        </button>
                        <button onClick={() => deleteTrans(t.id)} className="text-rose-500 hover:bg-rose-50 p-2 rounded-lg transition-colors" title="Sil">
                          <i className="fa-solid fa-trash-can"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
                {transactions.filter(t => t.source === 'manual').length === 0 && (
                  <tr>
                    <td colSpan={4} className="p-16 text-center text-slate-400 italic">Manuel girilen işlem bulunmuyor.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ManualManager;

import React, { useState, useMemo } from 'react';
import { FlowPeriod, ProjectionType, Currency, Asset } from '../types';
import { formatMoney } from '../utils/calculations';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';

interface FlowDashboardProps {
  periods: FlowPeriod[];
  projectionType: ProjectionType;
  setProjectionType: (t: ProjectionType) => void;
  viewCurrency: Currency;
  assets: Asset[];
  setAssets: React.Dispatch<React.SetStateAction<Asset[]>>;
  eurRate: number;
}

const FlowDashboard: React.FC<FlowDashboardProps> = ({ 
  periods, projectionType, setProjectionType, viewCurrency, assets, setAssets, eurRate 
}) => {
  const [selectedDetails, setSelectedDetails] = useState<FlowPeriod | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const toggleAsset = (id: string) => {
    setAssets(prev => prev.map(a => a.id === id ? { ...a, included: !a.included } : a));
  };

  const filteredPeriods = useMemo(() => {
    if (!searchQuery.trim()) return periods;
    const query = searchQuery.toLowerCase();
    return periods.map(p => {
      // Periyodun detaylarında arama yap
      const filteredDetails: Record<string, number> = {};
      let hasMatch = p.label.toLowerCase().includes(query);

      // Fix: Cast Object.entries to [string, number][] to ensure 'amount' is treated as a number
      (Object.entries(p.details) as [string, number][]).forEach(([desc, amount]) => {
        if (desc.toLowerCase().includes(query)) {
          filteredDetails[desc] = amount;
          hasMatch = true;
        }
      });

      if (hasMatch) {
        return { ...p, details: Object.keys(filteredDetails).length > 0 ? filteredDetails : p.details };
      }
      return null;
    }).filter(p => p !== null) as FlowPeriod[];
  }, [periods, searchQuery]);

  // Grafik verisi (Daima tam liste kullanılır, sadece bakiye değişimi izlenir)
  const chartData = useMemo(() => {
    return periods.map(p => ({
      label: p.label,
      balance: parseFloat(p.balance.toFixed(2))
    }));
  }, [periods]);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Sidebar Controls */}
        <div className="space-y-6">
          <div className="bg-white p-5 rounded-2xl border shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <i className="fa-solid fa-sliders text-blue-600"></i> Projeksiyon
            </h3>
            <div className="grid grid-cols-3 gap-1 bg-slate-100 p-1 rounded-xl">
              {(['daily', 'weekly', 'monthly'] as ProjectionType[]).map(type => (
                <button
                  key={type}
                  onClick={() => setProjectionType(type)}
                  className={`py-2 rounded-lg text-[10px] font-black uppercase transition-all ${
                    projectionType === type ? 'bg-white shadow text-blue-700' : 'text-slate-400 hover:text-slate-800'
                  }`}
                >
                  {type === 'daily' ? 'Günlük' : type === 'weekly' ? 'Haftalık' : 'Aylık'}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white p-5 rounded-2xl border shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <i className="fa-solid fa-vault text-blue-600"></i> Aktif Varlıklar
            </h3>
            <div className="space-y-2 max-h-60 overflow-y-auto custom-scrollbar">
              {(assets || []).map(asset => (
                <label key={asset.id} className="flex items-center justify-between p-2 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors border border-transparent hover:border-slate-100">
                  <div className="flex items-center gap-3">
                    <input 
                      type="checkbox" 
                      checked={asset.included} 
                      onChange={() => toggleAsset(asset.id)}
                      className="w-4 h-4 text-blue-600 rounded"
                    />
                    <div className="flex flex-col">
                      <span className="text-sm font-semibold text-slate-700 truncate max-w-[120px]">{asset.name}</span>
                      <span className="text-[10px] text-slate-400 uppercase">{asset.subType}</span>
                    </div>
                  </div>
                  <span className="text-xs font-bold text-slate-600">
                    {formatMoney(asset.amount, asset.currency)}
                  </span>
                </label>
              ))}
              {(!assets || assets.length === 0) && <p className="text-xs text-slate-400 italic">Varlık tanımlanmamış.</p>}
            </div>
            <div className="mt-4 pt-4 border-t flex justify-between items-center">
              <span className="text-xs font-bold text-slate-400">Başlangıç Bakiyesi:</span>
              <span className="text-lg font-black text-blue-700">
                {formatMoney(periods[0]?.balance || 0, viewCurrency)}
              </span>
            </div>
          </div>
        </div>

        {/* Chart Area */}
        <div className="lg:col-span-3">
          <div className="bg-white p-6 rounded-2xl border shadow-sm h-[450px] flex flex-col overflow-hidden">
            <div className="flex items-center justify-between mb-6">
              <h3 className="font-bold text-slate-800 text-lg">Bakiye Projeksiyon Grafiği</h3>
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full bg-blue-500"></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Net Bakiye ({viewCurrency})</span>
                </div>
              </div>
            </div>
            <div className="flex-1 w-full relative">
              <div className="absolute inset-0">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorBalance" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.2}/>
                        <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis 
                      dataKey="label" 
                      tick={{fontSize: 9, fill: '#94a3b8'}} 
                      axisLine={false} 
                      tickLine={false} 
                      interval={projectionType === 'daily' ? 7 : 0}
                      height={40}
                    />
                    <YAxis 
                      tick={{fontSize: 10, fill: '#94a3b8'}} 
                      axisLine={false} 
                      tickLine={false} 
                      tickFormatter={(val) => val >= 1000 || val <= -1000 ? `${(val/1000).toFixed(0)}k` : val}
                      domain={['auto', 'auto']}
                    />
                    <Tooltip 
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '12px' }}
                      formatter={(val: number) => [formatMoney(val, viewCurrency), 'Net Bakiye']}
                      labelStyle={{ fontWeight: 'bold', marginBottom: '4px', color: '#1e293b' }}
                    />
                    <Area 
                      type="monotone" 
                      dataKey="balance" 
                      stroke="#3b82f6" 
                      strokeWidth={3} 
                      fillOpacity={1} 
                      fill="url(#colorBalance)" 
                      isAnimationActive={true}
                      animationDuration={800}
                    />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Detailed Table */}
      <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
        <div className="p-5 border-b flex flex-col md:flex-row md:items-center justify-between gap-4 bg-slate-50/50">
          <div>
            <h3 className="font-bold text-slate-800">Projeksiyon Veri Tablosu</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">{projectionType} Akış Planı</p>
          </div>
          <div className="relative">
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm"></i>
            <input 
              type="text" 
              placeholder="İşlem veya Tarih Ara..." 
              className="bg-white border border-slate-200 rounded-xl py-2.5 pl-11 pr-4 outline-none focus:ring-2 focus:ring-blue-500 w-full md:w-64 text-sm transition-all shadow-sm"
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
            />
          </div>
        </div>
        <div className="overflow-x-auto custom-scrollbar max-h-[600px]">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b sticky top-0 z-10 shadow-sm">
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Tarih / Dönem</th>
                <th className="p-4 text-xs font-bold text-green-600 uppercase tracking-wider text-right">Giriş (+)</th>
                <th className="p-4 text-xs font-bold text-rose-600 uppercase tracking-wider text-right">Çıkış (-)</th>
                <th className="p-4 text-xs font-bold text-slate-800 uppercase tracking-wider text-right">Bakiye</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-center">Detay</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredPeriods.map((p, idx) => (
                <tr key={idx} className={`hover:bg-slate-50 transition-colors ${p.start.getDay() === 0 || p.start.getDay() === 6 ? 'bg-slate-50/30' : ''}`}>
                  <td className="p-4 text-sm font-medium text-slate-600 whitespace-nowrap">{p.label}</td>
                  <td className="p-4 text-sm font-bold text-green-600 text-right">
                    {p.incomes > 0 ? formatMoney(p.incomes, viewCurrency) : '-'}
                  </td>
                  <td className="p-4 text-sm font-bold text-rose-600 text-right">
                    {p.expenses > 0 ? formatMoney(p.expenses, viewCurrency) : '-'}
                  </td>
                  <td className="p-4 text-sm font-black text-slate-800 text-right">
                    <span className={p.balance < 0 ? 'text-rose-600' : ''}>
                      {formatMoney(p.balance, viewCurrency)}
                    </span>
                  </td>
                  <td className="p-4 text-center">
                    {Object.keys(p.details).length > 0 && (
                      <button 
                        onClick={() => setSelectedDetails(p)}
                        className="text-[10px] font-black uppercase text-blue-600 hover:bg-blue-100 px-3 py-1.5 rounded-lg border border-blue-200 transition-all shadow-sm"
                      >
                        İncele
                      </button>
                    )}
                  </td>
                </tr>
              ))}
              {filteredPeriods.length === 0 && (
                <tr>
