import React, { useState, useEffect, useMemo } from 'react';
import { Asset, Check, RecurringRule, Transaction, CustomTab, ProjectionType, Currency } from './types';
import { calculateFlow } from './utils/calculations';
import { syncFromDb, saveToDb } from './services/firebaseService';

// Sub-components
import Sidebar from './components/Sidebar';
import FlowDashboard from './components/FlowDashboard';
import AssetManager from './components/AssetManager';
import CheckManager from './components/CheckManager';
import RecurringManager from './components/RecurringManager';
import ManualManager from './components/ManualManager';
import ExcelTabs from './components/ExcelTabs';
import AIChatAssistant from './components/AIChatAssistant';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('flow');
  const [eurRate, setEurRate] = useState(36.50);
  const [viewCurrency, setViewCurrency] = useState<Currency>('TL');
  const [projectionType, setProjectionType] = useState<ProjectionType>('daily');

  const [assets, setAssets] = useState<Asset[]>([]);
  const [checks, setChecks] = useState<Check[]>([]);
  const [manualTransactions, setManualTransactions] = useState<Transaction[]>([]);
  const [recurringRules, setRecurringRules] = useState<RecurringRule[]>([]);
  const [customTabs, setCustomTabs] = useState<CustomTab[]>([]);

  // Firebase Real-time Sync
  useEffect(() => {
    const unsubAssets = syncFromDb('assets', (data) => setAssets(data || []));
    const unsubChecks = syncFromDb('checks', (data) => setChecks(data || []));
    const unsubManual = syncFromDb('manualTransactions', (data) => setManualTransactions(data || []));
    const unsubRules = syncFromDb('recurringRules', (data) => setRecurringRules(data || []));
    const unsubTabs = syncFromDb('customTabs', (data) => setCustomTabs(data || []));

    fetchEurRate();

    return () => {
      unsubAssets(); unsubChecks(); unsubManual(); unsubRules(); unsubTabs();
    };
  }, []);

  const fetchEurRate = async () => {
    try {
      const response = await fetch('https://api.frankfurter.app/latest?from=EUR&to=TRY');
      if (response.ok) {
        const data = await response.json();
        setEurRate(data.rates.TRY);
      }
    } catch (e) { console.error("Rate fetch failed", e); }
  };

  const periods = useMemo(() => 
    calculateFlow(projectionType, assets, checks, manualTransactions, recurringRules, eurRate, viewCurrency),
    [projectionType, assets, checks, manualTransactions, recurringRules, eurRate, viewCurrency]
  );

  const handleUpdateAssets = (newAssets: Asset[]) => {
    setAssets(newAssets);
    saveToDb('assets', newAssets);
  };

  const handleUpdateChecks = (newChecks: Check[]) => {
    setChecks(newChecks);
    saveToDb('checks', newChecks);
  };

  const handleUpdateManual = (newManual: Transaction[]) => {
    setManualTransactions(newManual);
    saveToDb('manualTransactions', newManual);
  };

  const handleUpdateRules = (newRules: RecurringRule[]) => {
    setRecurringRules(newRules);
    saveToDb('recurringRules', newRules);
  };

  const handleUpdateTabs = (newTabs: CustomTab[]) => {
    setCustomTabs(newTabs);
    saveToDb('customTabs', newTabs);
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        customTabs={customTabs}
        setCustomTabs={handleUpdateTabs}
        onExport={() => alert("Firebase üzerinde verileriniz güvende.")}
        onImport={() => alert("Firebase veri yönetimi otomatiktir.")}
      />

      <main className="flex-1 p-4 lg:p-8 overflow-y-auto relative">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <h1 className="text-2xl font-bold text-slate-800 tracking-tight">FinFlow <span className="text-blue-600">Pro</span></h1>
            <p className="text-slate-500 text-sm">Finansal projeksiyonunuz (Firebase Cloud) üzerinden takip ediliyor.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3 bg-white p-2 rounded-xl shadow-sm border border-slate-100">
            <div className="flex items-center gap-2 px-3 border-r border-slate-100 pr-4">
              <span className="text-[10px] font-black text-slate-400 uppercase">1 EUR</span>
              <input 
                type="number" 
                value={eurRate} 
                onChange={(e) => setEurRate(Number(e.target.value))}
                className="w-16 text-sm font-bold bg-transparent outline-none border-b border-transparent focus:border-blue-500 transition-all"
              />
              <span className="text-xs font-bold text-slate-500">TL</span>
            </div>

            <div className="flex bg-slate-50 p-1 rounded-lg">
              <button onClick={() => setViewCurrency('TL')} className={`px-4 py-1.5 rounded-md text-[11px] font-black transition-all ${viewCurrency === 'TL' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>TL</button>
              <button onClick={() => setViewCurrency('EUR')} className={`px-4 py-1.5 rounded-md text-[11px] font-black transition-all ${viewCurrency === 'EUR' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>EUR</button>
            </div>
          </div>
        </header>

        <div className="pb-24">
          {activeTab === 'flow' && (
            <FlowDashboard 
              periods={periods} 
              projectionType={projectionType} 
              setProjectionType={setProjectionType}
              viewCurrency={viewCurrency}
              assets={assets}
              setAssets={handleUpdateAssets}
              eurRate={eurRate}
            />
          )}

          {activeTab === 'assets' && (
            <AssetManager assets={assets} setAssets={handleUpdateAssets} viewCurrency={viewCurrency} eurRate={eurRate} />
          )}

          {activeTab === 'checks' && (
            <CheckManager checks={checks} setChecks={handleUpdateChecks} />
          )}

          {activeTab === 'recurring' && (
            <RecurringManager rules={recurringRules} setRules={handleUpdateRules} />
          )}

          {activeTab === 'manual' && (
            <ManualManager transactions={manualTransactions} setTransactions={handleUpdateManual} />
          )}

          {activeTab.startsWith('cust-') && (
            <ExcelTabs 
              tabId={activeTab} 
              transactions={manualTransactions} 
              setTransactions={handleUpdateManual} 
              customTabs={customTabs}
              setCustomTabs={handleUpdateTabs}
            />
          )}
        </div>
      </main>

      <AIChatAssistant assets={assets} periods={periods} />
    </div>
  );
};

export default App;

