import { GoogleGenAI } from "@google/genai";
import { FlowPeriod, Asset } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeCashFlow = async (periods: FlowPeriod[]) => {
  const ai = getAI();
  const summary = periods
    .filter(p => p.incomes > 0 || p.expenses > 0)
    .map(p => ({
      period: p.label,
      bal: p.balance.toFixed(0)
    })).slice(0, 10);

  const prompt = `Nakit akışını analiz et. Sadece en önemli 1-2 cümleyi söyle. Vurgulu ve net ol:\n${JSON.stringify(summary)}`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });
    return { text: response.text || "Analiz yapılamadı." };
  } catch (error) {
    return { text: "Analiz hatası." };
  }
};

export const fetchMarketInsights = async () => {
  const ai = getAI();
  const prompt = `Türkiye ekonomisi için güncel enflasyon ve döviz kuru beklentilerini SADECE liste halinde, tarih belirterek özetle. 
  Giriş ve sonuç cümlesi istemiyorum. Sadece veri ver.

  Format:
  - [Ay/Yıl]: [Kısa Açıklama/Beklenti Verisi]

  Örnek:
  - Ocak 2025: TCMB Enflasyon Beklentisi %...
  - Şubat 2025: Piyasa USD Kuru Tahmini ...`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title,
      uri: chunk.web?.uri
    })).filter((s: any) => s.title && s.uri) || [];

    return {
      text: response.text || "Beklenti verisi bulunamadı.",
      sources: sources
    };
  } catch (error) {
    return { text: "Piyasa verileri şu an çekilemiyor.", sources: [] };
  }
};

export const chatWithAssistant = async (userMessage: string, context: { assets: Asset[], periods: FlowPeriod[] }) => {
  const ai = getAI();
  const systemPrompt = `Finans asistanısın. Kısa, teknik ve verilere dayalı konuş. Tek cümlelik, net yanıtlar ver.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userMessage,
      config: { systemInstruction: systemPrompt }
    });
    return response.text || "Yanıt alınamadı.";
  } catch (error) {
    return "Bağlantı hatası.";
  }
};

