import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Asset, Check, RecurringRule, Transaction, CustomTab, ProjectionType, Currency } from './types';
import { calculateFlow } from './utils/calculations';
import { syncPath, updatePath } from './services/firebaseService';

// Sub-components
import Sidebar from './components/Sidebar';
import FlowDashboard from './components/FlowDashboard';
import AssetManager from './components/AssetManager';
import CheckManager from './components/CheckManager';
import RecurringManager from './components/RecurringManager';
import ManualManager from './components/ManualManager';
import ExcelTabs from './components/ExcelTabs';
import AIChatAssistant from './components/AIChatAssistant';
import AIAnalysisTab from './components/AIAnalysisTab';

const App: React.FC = () => {
  // State
  const [activeTab, setActiveTab] = useState('flow');
  const [eurRate, setEurRate] = useState(36.50);
  const [viewCurrency, setViewCurrency] = useState<Currency>('TL');
  const [projectionType, setProjectionType] = useState<ProjectionType>('daily');

  const [assets, setAssets] = useState<Asset[]>([]);
  const [checks, setChecks] = useState<Check[]>([]);
  const [manualTransactions, setManualTransactions] = useState<Transaction[]>([]);
  const [recurringRules, setRecurringRules] = useState<RecurringRule[]>([]);
  const [customTabs, setCustomTabs] = useState<CustomTab[]>([]);

  // Refs to prevent recursive updates
  const isInitialLoad = useRef({
    assets: true,
    checks: true,
    manual: true,
    rules: true,
    tabs: true
  });

  // 1. Firebase Listeners (Cloud -> App)
  useEffect(() => {
    const unsubAssets = syncPath('assets', (data) => {
      setAssets(data || []);
      isInitialLoad.current.assets = false;
    });
    const unsubChecks = syncPath('checks', (data) => {
      setChecks(data || []);
      isInitialLoad.current.checks = false;
    });
    const unsubManual = syncPath('manualTransactions', (data) => {
      setManualTransactions(data || []);
      isInitialLoad.current.manual = false;
    });
    const unsubRules = syncPath('recurringRules', (data) => {
      setRecurringRules(data || []);
      isInitialLoad.current.rules = false;
    });
    const unsubTabs = syncPath('customTabs', (data) => {
      setCustomTabs(data || []);
      isInitialLoad.current.tabs = false;
    });

    fetchEurRate();

    return () => {
      unsubAssets();
      unsubChecks();
      unsubManual();
      unsubRules();
      unsubTabs();
    };
  }, []);

  // 2. Firebase Writers (App -> Cloud)
  // Sadece veri gerçekten değiştiğinde ve ilk yükleme bittikten sonra çalışır
  useEffect(() => { if (!isInitialLoad.current.assets) updatePath('assets', assets); }, [assets]);
  useEffect(() => { if (!isInitialLoad.current.checks) updatePath('checks', checks); }, [checks]);
  useEffect(() => { if (!isInitialLoad.current.manual) updatePath('manualTransactions', manualTransactions); }, [manualTransactions]);
  useEffect(() => { if (!isInitialLoad.current.rules) updatePath('recurringRules', recurringRules); }, [recurringRules]);
  useEffect(() => { if (!isInitialLoad.current.tabs) updatePath('customTabs', customTabs); }, [customTabs]);

  const fetchEurRate = async () => {
    try {
      const response = await fetch('https://api.frankfurter.app/latest?from=EUR&to=TRY');
      if (response.ok) {
        const data = await response.json();
        setEurRate(data.rates.TRY);
      }
    } catch (e) { console.error("Rate fetch failed", e); }
  };

  const periods = useMemo(() => 
    calculateFlow(projectionType, assets, checks, manualTransactions, recurringRules, eurRate, viewCurrency),
    [projectionType, assets, checks, manualTransactions, recurringRules, eurRate, viewCurrency]
  );

  const handleExport = () => {
    const data = { assets, checks, manualTransactions, recurringRules, customTabs };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `primus-cashflow-backup-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  };

  const handleImport = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'application/json';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (re: any) => {
        try {
          const data = JSON.parse(re.target.result as string);
          // Firebase'e yaz, state zaten listener üzerinden güncellenecek
          if (data.assets) updatePath('assets', data.assets);
          if (data.checks) updatePath('checks', data.checks);
          if (data.manualTransactions) updatePath('manualTransactions', data.manualTransactions);
          if (data.recurringRules) updatePath('recurringRules', data.recurringRules);
          if (data.customTabs) updatePath('customTabs', data.customTabs);
          alert("Veriler buluta yüklendi ve tüm cihazlarla eşitlendi.");
        } catch (err) { alert("Geçersiz yedek dosyası."); }
      };
      reader.readAsText(file);
    };
    input.click();
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        customTabs={customTabs}
        setCustomTabs={setCustomTabs}
        onExport={handleExport}
        onImport={handleImport}
      />

      <main className="flex-1 p-4 lg:p-8 overflow-y-auto relative">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div className="flex items-center gap-3">
            <div className="bg-green-500 w-2 h-2 rounded-full animate-pulse shadow-lg shadow-green-200" title="Canlı Bağlantı Aktif"></div>
            <div>
              <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Primus Coating <span className="text-blue-600 underline decoration-blue-200 underline-offset-4">Cashflow</span></h1>
              <p className="text-slate-500 text-sm">Gerçek zamanlı bulut senkronizasyonlu finans yönetim sistemi.</p>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-3 bg-white p-2 rounded-xl shadow-sm border border-slate-100">
            <div className="flex items-center gap-2 px-3 border-r border-slate-100 pr-4">
              <span className="text-[10px] font-black text-slate-400 uppercase">1 EUR</span>
              <input 
                type="number" 
                value={eurRate} 
                onChange={(e) => setEurRate(Number(e.target.value))}
                className="w-16 text-sm font-bold bg-transparent outline-none border-b border-transparent focus:border-blue-500 transition-all"
              />
              <span className="text-xs font-bold text-slate-500">TL</span>
            </div>

            <div className="flex bg-slate-50 p-1 rounded-lg">
              <button 
                onClick={() => setViewCurrency('TL')}
                className={`px-4 py-1.5 rounded-md text-[11px] font-black transition-all ${viewCurrency === 'TL' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                TL
              </button>
              <button 
                onClick={() => setViewCurrency('EUR')}
                className={`px-4 py-1.5 rounded-md text-[11px] font-black transition-all ${viewCurrency === 'EUR' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                EUR
              </button>
            </div>
          </div>
        </header>

        <div className="pb-24">
          {activeTab === 'flow' && (
            <FlowDashboard 
              periods={periods} 
              projectionType={projectionType} 
              setProjectionType={setProjectionType}
              viewCurrency={viewCurrency}
              assets={assets}
              setAssets={setAssets}
              eurRate={eurRate}
            />
          )}

          {activeTab === 'ai-analysis' && (
            <AIAnalysisTab periods={periods} viewCurrency={viewCurrency} />
          )}

          {activeTab === 'assets' && (
            <AssetManager assets={assets} setAssets={setAssets} viewCurrency={viewCurrency} eurRate={eurRate} />
          )}

          {activeTab === 'checks' && (
            <CheckManager checks={checks} setChecks={setChecks} />
          )}

          {activeTab === 'recurring' && (
            <RecurringManager rules={recurringRules} setRules={setRecurringRules} />
          )}

          {activeTab === 'manual' && (
            <ManualManager transactions={manualTransactions} setTransactions={setManualTransactions} />
          )}

          {activeTab.startsWith('cust-') && (
            <ExcelTabs 
              tabId={activeTab} 
              transactions={manualTransactions} 
              setTransactions={setManualTransactions} 
              customTabs={customTabs}
              setCustomTabs={setCustomTabs}
            />
          )}
        </div>
      </main>

      <AIChatAssistant assets={assets} periods={periods} />
    </div>
  );
};

