  appId: "1:1043517372772:web:797b0418c90e2ab1c96271"
};

// Singleton initialization
const app = getApps().length === 0 ? initializeApp(firebaseConfig) : getApp();

// europe-west1 bölgesi için URL'yi açıkça belirtmek daha güvenlidir
const db = getDatabase(app, firebaseConfig.databaseURL);

/**
 * Dinamik olarak bir yolu Firebase'de dinler ve React state'ini günceller.
 */
export const syncPath = (path: string, callback: (data: any) => void) => {
  const dbRef = ref(db, path);
  onValue(dbRef, (snapshot) => {
    callback(snapshot.val());
  }, (error) => {
    console.error(`Firebase Sync Error [${path}]:`, error);
  });
  return () => off(dbRef);
};

/**
 * Veriyi Firebase'e kaydeder.
 */
export const updatePath = async (path: string, data: any) => {
  if (data === undefined) return;
  try {
    const dbRef = ref(db, path);
    // Veriyi temizleyerek kaydet (undefined değerleri null yapar)
    const cleanData = JSON.parse(JSON.stringify(data));
    await set(dbRef, cleanData);
  } catch (error) {
    console.error(`Firebase Update Error [${path}]:`, error);
  }
};

