  const [viewCurrency, setViewCurrency] = useState<Currency>('TL');
  const [projectionType, setProjectionType] = useState<ProjectionType>('daily');
  const [isSynced, setIsSynced] = useState(false);

  const [assets, setAssets] = useState<Asset[]>([]);
  const [checks, setChecks] = useState<Check[]>([]);
  const [manualTransactions, setManualTransactions] = useState<Transaction[]>([]);
  const [recurringRules, setRecurringRules] = useState<RecurringRule[]>([]);
  const [customTabs, setCustomTabs] = useState<CustomTab[]>([]);

  // Firebase Realtime Sync
  useEffect(() => {
    const unsubscribeAssets = syncPath('assets', (data) => {
      setAssets(data || []);
      setIsSynced(true);
    });
    const unsubscribeChecks = syncPath('checks', (data) => setChecks(data || []));
    const unsubscribeManual = syncPath('manualTransactions', (data) => setManualTransactions(data || []));
    const unsubscribeRules = syncPath('recurringRules', (data) => setRecurringRules(data || []));
    const unsubscribeTabs = syncPath('customTabs', (data) => setCustomTabs(data || []));

    fetchEurRate();

    return () => {
      unsubscribeAssets();
      unsubscribeChecks();
      unsubscribeManual();
      unsubscribeRules();
      unsubscribeTabs();
    };
  }, []);

  // Firebase Write Wrappers
  const handleSetAssets = (newAssets: any) => {
    const data = typeof newAssets === 'function' ? newAssets(assets) : newAssets;
    updatePath('assets', data);
  };

  const handleSetChecks = (newChecks: any) => {
    const data = typeof newChecks === 'function' ? newChecks(checks) : newChecks;
    updatePath('checks', data);
  };

  const handleSetManual = (newManual: any) => {
    const data = typeof newManual === 'function' ? newManual(manualTransactions) : newManual;
    updatePath('manualTransactions', data);
  };

  const handleSetRules = (newRules: any) => {
    const data = typeof newRules === 'function' ? newRules(recurringRules) : newRules;
    updatePath('recurringRules', data);
  };

  const handleSetTabs = (newTabs: any) => {
    const data = typeof newTabs === 'function' ? newTabs(customTabs) : newTabs;
    updatePath('customTabs', data);
  };

  const fetchEurRate = async () => {
    try {
      const response = await fetch('https://api.frankfurter.app/latest?from=EUR&to=TRY');
      if (response.ok) {
        const data = await response.json();
        setEurRate(data.rates.TRY);
      }
    } catch (e) { console.error("Rate fetch failed", e); }
  };

  const periods = useMemo(() => 
    calculateFlow(projectionType, assets, checks, manualTransactions, recurringRules, eurRate, viewCurrency),
    [projectionType, assets, checks, manualTransactions, recurringRules, eurRate, viewCurrency]
  );

  const handleExport = () => {
    const data = { assets, checks, manualTransactions, recurringRules, customTabs };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `primus-cashflow-backup-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  };

  const handleImport = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'application/json';
    input.onchange = (e: any) => {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (re: any) => {
        try {
          const data = JSON.parse(re.target.result as string);
          if (data.assets) handleSetAssets(data.assets);
          if (data.checks) handleSetChecks(data.checks);
          if (data.manualTransactions) handleSetManual(data.manualTransactions);
          if (data.recurringRules) handleSetRules(data.recurringRules);
          if (data.customTabs) handleSetTabs(data.customTabs);
          alert("Veriler Firebase'e başarıyla aktarıldı.");
        } catch (err) { alert("Geçersiz yedek dosyası."); }
      };
      reader.readAsText(file);
    };
    input.click();
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        customTabs={customTabs}
        setCustomTabs={handleSetTabs}
        onExport={handleExport}
        onImport={handleImport}
      />

      <main className="flex-1 p-4 lg:p-8 overflow-y-auto relative">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <div className="flex items-center gap-3 mb-1">
              <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Primus Coating <span className="text-blue-600 underline decoration-blue-200 underline-offset-4 font-black">CASHFLOW</span></h1>
              {isSynced && (
                <div className="flex items-center gap-1.5 bg-green-50 text-green-700 px-2 py-1 rounded-full border border-green-100 shadow-sm animate-in fade-in slide-in-from-left-2">
                  <span className="relative flex h-2 w-2">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                  </span>
                  <span className="text-[10px] font-black uppercase tracking-widest">Cloud Sync</span>
                </div>
              )}
            </div>
            <p className="text-slate-500 text-sm">Online Kurumsal Projeksiyon Sistemi v3.5 Pro</p>
          </div>

          <div className="flex flex-wrap items-center gap-3 bg-white p-2 rounded-xl shadow-sm border border-slate-100">
            <div className="flex items-center gap-2 px-3 border-r border-slate-100 pr-4">
