import { initializeApp } from "firebase/app";
import { getDatabase, ref, set, onValue, off } from "firebase/database";

// NOT: Bu bilgileri Firebase Console -> Proje Ayarları -> Web Uygulaması Ekle kısmından almalısınız.
// Buradaki bilgiler örnek teşkil eder.
const firebaseConfig = {
  apiKey: "YOUR_API_KEY",
  authDomain: "YOUR_PROJECT_ID.firebaseapp.com",
  databaseURL: "https://YOUR_PROJECT_ID-default-rtdb.firebaseio.com",
  projectId: "YOUR_PROJECT_ID",
  storageBucket: "YOUR_PROJECT_ID.appspot.com",
  messagingSenderId: "SENDER_ID",
  appId: "APP_ID"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const db = getDatabase(app);

/**
 * Dinamik olarak bir yolu Firebase'de dinler ve React state'ini günceller.
 */
export const syncPath = (path: string, callback: (data: any) => void) => {
  const dbRef = ref(db, path);
  onValue(dbRef, (snapshot) => {
    callback(snapshot.val());
  }, (error) => {
    console.error(`Firebase Sync Error [${path}]:`, error);
  });

  // Temizlik fonksiyonu (unsubscribe)
  return () => off(dbRef);
};

/**
 * Veriyi Firebase'e kaydeder.
 */
export const updatePath = async (path: string, data: any) => {
  if (data === undefined) return;
  try {
    const dbRef = ref(db, path);
    await set(dbRef, data);
  } catch (error) {
    console.error(`Firebase Update Error [${path}]:`, error);
    throw error;
  }
};

