        } catch (err) { alert("Geçersiz yedek dosyası."); }
      };
      reader.readAsText(file);
    };
    input.click();
  };

  return (
    <div className="flex min-h-screen bg-slate-50 relative">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(id) => {
          setActiveTab(id);
          setIsMobileMenuOpen(false);
        }} 
        customTabs={customTabs}
        setCustomTabs={handleSetTabs}
        onExport={handleExport}
        onImport={handleImport}
        isMobileOpen={isMobileMenuOpen}
        setIsMobileOpen={setIsMobileMenuOpen}
      />

      <main className="flex-1 p-4 lg:p-8 overflow-y-auto relative w-full">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsMobileMenuOpen(true)}
              className="lg:hidden bg-white p-3 rounded-xl border border-slate-200 text-slate-600 shadow-sm"
            >
              <i className="fa-solid fa-bars-staggered text-lg"></i>
            </button>

            <div>
              <div className="flex items-center gap-3 mb-1">
                <h1 className="text-xl md:text-2xl font-bold text-slate-800 tracking-tight">
                  Primus Coating <span className="text-blue-600 underline decoration-blue-200 underline-offset-4 font-black">CASHFLOW</span>
                </h1>
                <div className={`flex items-center gap-1.5 px-2 py-1 rounded-full border transition-all ${isCloudSynced ? 'bg-green-50 text-green-600 border-green-200' : 'bg-amber-50 text-amber-600 border-amber-200'}`}>
                  <i className={`fa-solid ${isCloudSynced ? 'fa-cloud-check' : 'fa-cloud-arrow-up'} text-[10px]`}></i>
                  <span className="text-[10px] font-black uppercase tracking-widest">{isCloudSynced ? 'Online' : 'Syncing...'}</span>
                </div>
