const db = getFirestore(app);

/**
 * Firestore'da bir dökümanı dinler ve React state'ini günceller.
 * Path formatı: "collection/document" (Örn: "cashflow/assets")
 */
export const syncPath = (path: string, callback: (data: any) => void) => {
  try {
    const parts = path.split('/');
    if (parts.length < 2) {
      console.error("Firestore path must contain collection and document ID (e.g. 'cashflow/assets')");
      return () => {};
    }

    const [colName, docId] = parts;
    const docRef = doc(db, colName, docId);

    const unsubscribe = onSnapshot(docRef, (snapshot) => {
      if (snapshot.exists()) {
        // Firestore dökümanları her zaman obje olmalıdır, biz veriyi "value" key'inde tutuyoruz.
        callback(snapshot.data().value);
      } else {
        callback(null);
      }
    }, (error) => {
      console.error(`Firestore Sync Error [${path}]:`, error);
    });

    return unsubscribe;
  } catch (err) {
    console.error(`Firestore Connection Error [${path}]:`, err);
    return () => {}; 
  }
};

/**
 * Veriyi Firestore'da bir dökümana kaydeder.
 */
export const updatePath = async (path: string, data: any) => {
  if (data === undefined) return;
  try {
    const parts = path.split('/');
    if (parts.length < 2) throw new Error("Invalid path for Firestore");

    const [colName, docId] = parts;
    const docRef = doc(db, colName, docId);

    // Firestore'da array veya direkt değeri saklamak için bir obje içine sarıyoruz.
    await setDoc(docRef, { 
      value: data,
      updatedAt: new Date().toISOString() 
    }, { merge: true });

  } catch (error) {
    console.error(`Firestore Update Error [${path}]:`, error);
    throw error;
  }
};

