/**
 * Establishes a real-time sync with a specific Firestore document path.
 * @param path Format: 'collection/documentId'
 * @param callback Function to receive data updates
 * @returns Unsubscribe function
 */
export const syncPath = (path: string, callback: (data: any) => void) => {
  const currentDb = initializeFirestore();

  if (!currentDb) {
    console.warn(`Firestore not available for sync [${path}]. Retrying in 3 seconds...`);
    const retryTimeout = setTimeout(() => syncPath(path, callback), 3000);
    return () => clearTimeout(retryTimeout);
  }

  try {
    const parts = path.split('/');
    if (parts.length < 2) {
      console.error(`Invalid Firestore path: ${path}`);
      return () => {};
    }

    const [collection, documentId] = parts;
    const docRef = doc(currentDb, collection, documentId);

    return onSnapshot(docRef, (snapshot) => {
      if (snapshot.exists()) {
        callback(snapshot.data().value);
      } else {
        callback(null);
      }
    }, (error) => {
      console.error(`Firestore Sync Error [${path}]:`, error);
    });
  } catch (err) {
    console.error(`Firestore Setup Error [${path}]:`, err);
    return () => {};
  }
};

/**
 * Updates a document in Firestore at the given path.
 * @param path Format: 'collection/documentId'
 * @param data The data to store (wrapped in a {value: ...} property for consistency)
 */
export const updatePath = async (path: string, data: any) => {
  const currentDb = initializeFirestore();

  if (!currentDb || data === undefined) {
    console.warn(`Firestore not ready for update [${path}].`);
    return;
  }

  try {
    const parts = path.split('/');
    if (parts.length < 2) return;

    const [collection, documentId] = parts;
    const docRef = doc(currentDb, collection, documentId);

    await setDoc(docRef, { 
      value: data,
      lastUpdate: new Date().toISOString()
    }, { merge: true });
  } catch (error) {
    console.error(`Firestore Update Error [${path}]:`, error);
  }
};

