    return dbInstance;
  } catch (error) {
    console.error("Critical Firebase Initialization Error:", error);
    return null;
  }
};

/**
 * Firestore instance'ını döndürür, hazır değilse ilklendirmeyi dener.
 */
const getDb = (): Firestore | null => {
  return dbInstance || initializeFirebase();
};

/**
 * Belirli bir döküman yolu için gerçek zamanlı senkronizasyon başlatır.
 * Firestore hazır değilse 2 saniye sonra otomatik yeniden dener.
 */
export const syncPath = (path: string, callback: (data: any) => void): (() => void) => {
  const db = getDb();

  if (!db) {
    console.warn(`Firestore initialization delayed for [${path}]. Retrying in 2 seconds...`);
    const retryTimeout = setTimeout(() => syncPath(path, callback), 2000);
    return () => clearTimeout(retryTimeout);
  }

  try {
    const parts = path.split('/');
    if (parts.length < 2) {
      console.error(`Invalid Firestore path: ${path}`);
      return () => {};
    }

    const [collection, documentId] = parts;
    const docRef = doc(db, collection, documentId);

    return onSnapshot(docRef, (snapshot) => {
      if (snapshot.exists()) {
        callback(snapshot.data().value);
      } else {
        callback(null);
      }
    }, (error) => {
      console.error(`Firestore Sync Error [${path}]:`, error);
      // Bağlantı koparsa veya izin hatası alınırsa sessizce yeniden deneme mekanizması onSnapshot içinde mevcuttur.
    });
  } catch (err) {
    console.error(`Firestore Setup Error [${path}]:`, err);
    return () => {};
  }
};

/**
 * Firestore'daki bir dökümanı günceller.
 * Firestore hazır değilse işlemi kuyruğa alır veya kısa süre sonra yeniden dener.
 */
export const updatePath = async (path: string, data: any, retryCount = 0) => {
  const db = getDb();

  if (!db) {
    if (retryCount < 5) {
      console.warn(`Firestore not ready for update at [${path}]. Retrying (Attempt ${retryCount + 1}/5)...`);
      setTimeout(() => updatePath(path, data, retryCount + 1), 1000 * (retryCount + 1));
    } else {
      console.error(`Firestore Update failed after 5 retries for [${path}]. Data loss possible.`);
    }
    return;
  }

  if (data === undefined) {
    console.warn(`Attempted to update [${path}] with undefined data. Skipping.`);
    return;
  }

  try {
    const parts = path.split('/');
    if (parts.length < 2) return;

    const [collection, documentId] = parts;
    const docRef = doc(db, collection, documentId);

    await setDoc(docRef, { 
      value: data,
      lastUpdate: new Date().toISOString()
    }, { merge: true });
  } catch (error) {
    console.error(`Firestore Update Error [${path}]:`, error);
    // Beklenmedik bir hata durumunda tek seferlik yeniden deneme
    if (retryCount < 1) {
       setTimeout(() => updatePath(path, data, retryCount + 1), 2000);
    }
  }
};

