import { initializeApp, getApps, getApp, FirebaseApp } from "firebase/app";
import { getFirestore, doc, setDoc, onSnapshot, Firestore, enableIndexedDbPersistence } from "firebase/firestore";

const firebaseConfig = {
  apiKey: "AIzaSyClUNt93ds2MQVolB9L5L6tGJlF0hdNTIQ",
  authDomain: "barlastestcashflow.firebaseapp.com",
  projectId: "barlastestcashflow",
  storageBucket: "barlastestcashflow.firebasestorage.app",
  messagingSenderId: "457571851448",
  appId: "1:457571851448:web:11510e555d43fa2041284d"
};

let dbInstance: Firestore | null = null;
let persistenceEnabled = false;

/**
 * Firebase'i ve Firestore'u güvenli bir şekilde ilklendirir.
 */
const getDb = (): Firestore | null => {
  if (dbInstance) return dbInstance;

  try {
    const apps = getApps();
    const app = apps.length > 0 ? getApp() : initializeApp(firebaseConfig);

    // Firestore instance'ını al (Instance henüz oluşturulmamışsa hata fırlatabilir, bu yüzden try-catch içinde)
    dbInstance = getFirestore(app);

    // Offline veri desteği
    if (!persistenceEnabled && typeof window !== "undefined" && dbInstance) {
      persistenceEnabled = true;
      enableIndexedDbPersistence(dbInstance).catch((err) => {
        if (err.code === 'failed-precondition') {
          console.warn("Birden fazla sekme açık, offline mod devre dışı.");
        } else if (err.code === 'unimplemented') {
          console.warn("Tarayıcı offline modu desteklemiyor.");
        }
      });
    }

    return dbInstance;
  } catch (error) {
    console.error("Firebase Initialization Error:", error);
    return null;
  }
};

/**
 * Veri senkronizasyonu için Firestore onSnapshot kullanımı.
 */
export const syncPath = (path: string, callback: (data: any) => void): (() => void) => {
  const db = getDb();

  if (!db) {
    console.warn(`Firestore not ready for path: ${path}. Retrying...`);
    const retryTimeout = setTimeout(() => syncPath(path, callback), 2000);
    return () => clearTimeout(retryTimeout);
  }

  try {
    const parts = path.split('/');
    if (parts.length < 2) return () => {};

    const [collectionName, docId] = parts;
    const docRef = doc(db, collectionName, docId);

    return onSnapshot(docRef, (snapshot) => {
      if (snapshot.exists()) {
        callback(snapshot.data().value);
      } else {
        callback(null);
      }
    }, (error) => {
      console.error(`Sync error (${path}):`, error);
      // Bağlantı hatalarında 10 saniye sonra tekrar dene
      if (error.code !== 'permission-denied') {
        setTimeout(() => syncPath(path, callback), 10000);
      }
    });
  } catch (err) {
    console.error(`Setup error (${path}):`, err);
    return () => {};
  }
};

/**
 * Veri güncelleme fonksiyonu.
 */
export const updatePath = async (path: string, data: any, retryCount = 0) => {
  if (data === undefined) return;

  const db = getDb();

  if (!db) {
    if (retryCount < 5) {
      const delay = Math.pow(2, retryCount) * 1000;
      setTimeout(() => updatePath(path, data, retryCount + 1), delay);
    }
    return;
  }

  try {
    const parts = path.split('/');
    if (parts.length < 2) return;
    const [collectionName, docId] = parts;
    const docRef = doc(db, collectionName, docId);

    await setDoc(docRef, { 
      value: data,
      updatedAt: new Date().toISOString()
    }, { merge: true });
  } catch (error) {
    console.error(`Update error (${path}):`, error);
    if (retryCount < 3) {
      setTimeout(() => updatePath(path, data, retryCount + 1), 2000);
    }
  }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
