            <div className="flex items-center justify-between px-3 py-2 mb-1">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Özel Takip</p>
              <button onClick={handleAddTab} className="bg-blue-50 text-blue-600 w-6 h-6 rounded-lg flex items-center justify-center">
                <i className="fa-solid fa-plus text-[10px]"></i>
              </button>
            </div>
            <div className="space-y-1">
              {customTabs.map(tab => (
                <button
                  key={tab.id}
