      {isMobileOpen && (
        <div 
          className="lg:hidden fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[70]"
          onClick={() => setIsMobileOpen?.(false)}
        />
      )}

      <div className={`
        fixed inset-y-0 left-0 z-[80] w-72 bg-white border-r flex flex-col transition-transform duration-300 transform
        lg:translate-x-0 lg:static lg:h-screen lg:z-auto
        ${isMobileOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}
      `}>
        <div className="p-6 border-b flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-slate-900 p-2 rounded-lg">
              <i className="fa-solid fa-layer-group text-white"></i>
            </div>
            <div className="flex flex-col">
                <span className="font-bold text-sm tracking-tight leading-none text-slate-800">Primus Coating</span>
                <span className="text-blue-600 font-black text-xs">CASHFLOW</span>
            </div>
          </div>
          <button onClick={() => setIsMobileOpen?.(false)} className="lg:hidden p-2 text-slate-400">
            <i className="fa-solid fa-xmark text-xl"></i>
          </button>
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto custom-scrollbar">
          <p className="px-3 py-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">Yönetim</p>
          {menuItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-3 py-3 rounded-xl transition-all font-semibold ${
                activeTab === item.id 
                ? 'bg-blue-600 text-white shadow-lg' 
                : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
              }`}
            >
              <i className={`fa-solid ${item.icon} w-5 text-center`}></i>
              <span className="text-sm">{item.label}</span>
            </button>
          ))}

          <div className="pt-6">
            <div className="flex items-center justify-between px-3 py-2 mb-1">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Özel Takip</p>
              <button onClick={handleAddTab} className="bg-blue-50 text-blue-600 w-6 h-6 rounded-lg flex items-center justify-center">
                <i className="fa-solid fa-plus text-[10px]"></i>
              </button>
            </div>
            <div className="space-y-1">
              {customTabs.map(tab => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all font-semibold ${
                    activeTab === tab.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
                  }`}
                >
                  <i className="fa-solid fa-folder-open w-5 text-center"></i>
                  <span className="truncate text-sm">{tab.name}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="pt-6">
            <p className="px-3 py-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">Yedekleme</p>
            <button onClick={onExport} className="w-full flex items-center gap-3 px-3 py-2.5 text-slate-500 hover:text-blue-600 text-sm font-semibold transition-colors">
              <i className="fa-solid fa-download w-5 text-center"></i>
              Verileri Yedekle
            </button>
            <button onClick={onImport} className="w-full flex items-center gap-3 px-3 py-2.5 text-slate-500 hover:text-blue-600 text-sm font-semibold transition-colors">
              <i className="fa-solid fa-upload w-5 text-center"></i>
              Yedeği Yükle
            </button>
          </div>
        </nav>

        <div className="p-4 mt-auto">
          <div className="bg-blue-600 rounded-2xl p-4 text-white flex items-center justify-between shadow-xl">
            <div className="flex flex-col">
              <p className="text-[10px] font-bold opacity-80 uppercase">Depolama</p>
              <p className="text-xs font-black">FIRESTONE CLOUD</p>
            </div>
            <div className="w-8 h-8 rounded-full bg-white/20 flex items-center justify-center">
              <i className="fa-solid fa-cloud text-[12px]"></i>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

